const WebSocket = require('ws');
const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', function connection(ws) {
  ws.on('message', function incoming(message) {
    const command = JSON.parse(message);
    processCommand(command);
  });
});

function processCommand(command) {
  switch (command.type) {
    case 'build':
      // Logic to build a unit or structure
      console.log(`Building ${command.unit} at ${command.location}`);
      break;
    case 'attack':
      // Logic to initiate an attack
      console.log(`Attacking target at ${command.targetLocation}`);
      break;
    case 'move':
      // Logic to move units
      console.log(`Moving ${command.units} from ${command.from} to ${command.to}`);
      break;
    default:
      console.log('Unknown command:', command);
  }
}